3367   /// Insert disconnected VPBlockBase \p NewBlock after \p BlockPtr. Add \p
3368   /// NewBlock as successor of \p BlockPtr and \p BlockPtr as predecessor of \p
3369   /// NewBlock, and propagate \p BlockPtr parent to \p NewBlock. \p BlockPtr's
3370   /// successors are moved from \p BlockPtr to \p NewBlock. \p NewBlock must
3371   /// have neither successors nor predecessors.
3372   static void insertBlockAfter(VPBlockBase *NewBlock, VPBlockBase *BlockPtr) {
3373     assert(NewBlock->getSuccessors().empty() &&
3374            NewBlock->getPredecessors().empty() &&
3375            "Can't insert new block with predecessors or successors.");
3376     NewBlock->setParent(BlockPtr->getParent());
3377     SmallVector<VPBlockBase *> Succs(BlockPtr->successors());
3378     for (VPBlockBase *Succ : Succs) {
3379       disconnectBlocks(BlockPtr, Succ);
3380       connectBlocks(NewBlock, Succ);
3381     }
3382     connectBlocks(BlockPtr, NewBlock);
3383   }
3384 
3385   /// Insert disconnected VPBlockBases \p IfTrue and \p IfFalse after \p
3386   /// BlockPtr. Add \p IfTrue and \p IfFalse as succesors of \p BlockPtr and \p
3387   /// BlockPtr as predecessor of \p IfTrue and \p IfFalse. Propagate \p BlockPtr
3388   /// parent to \p IfTrue and \p IfFalse. \p BlockPtr must have no successors
3389   /// and \p IfTrue and \p IfFalse must have neither successors nor
3390   /// predecessors.
3391   static void insertTwoBlocksAfter(VPBlockBase *IfTrue, VPBlockBase *IfFalse,
3392                                    VPBlockBase *BlockPtr) {
3393     assert(IfTrue->getSuccessors().empty() &&
3394            "Can't insert IfTrue with successors.");
3395     assert(IfFalse->getSuccessors().empty() &&
3396            "Can't insert IfFalse with successors.");
3397     BlockPtr->setTwoSuccessors(IfTrue, IfFalse);
3398     IfTrue->setPredecessors({BlockPtr});
3399     IfFalse->setPredecessors({BlockPtr});
3400     IfTrue->setParent(BlockPtr->getParent());
3401     IfFalse->setParent(BlockPtr->getParent());
3402   }
3403 
3404   /// Connect VPBlockBases \p From and \p To bi-directionally. Append \p To to
3405   /// the successors of \p From and \p From to the predecessors of \p To. Both
3406   /// VPBlockBases must have the same parent, which can be null. Both
3407   /// VPBlockBases can be already connected to other VPBlockBases.
3408   static void connectBlocks(VPBlockBase *From, VPBlockBase *To) {
3409     assert((From->getParent() == To->getParent()) &&
3410            "Can't connect two block with different parents");
3411     assert(From->getNumSuccessors() < 2 &&
3412            "Blocks can't have more than two successors.");
3413     From->appendSuccessor(To);
3414     To->appendPredecessor(From);
3415   }
3416 
3417   /// Disconnect VPBlockBases \p From and \p To bi-directionally. Remove \p To
3418   /// from the successors of \p From and \p From from the predecessors of \p To.
3419   static void disconnectBlocks(VPBlockBase *From, VPBlockBase *To) {
3420     assert(To && "Successor to disconnect is null.");
3421     From->removeSuccessor(To);
3422     To->removePredecessor(From);
3423   }
